import React from 'react'
import "../Navigation/Nav.css"
import { Link } from 'react-router-dom'
import { useState, useEffect } from 'react'
import Logo from "../../assets/pikachu.png"
import { useNavigate } from 'react-router-dom'
import { useParams } from 'react-router-dom'


const Nav = () => {
  const PokemonDetail = () => {
    const {name} = useParams(); 
    const [pokemon, setPokemon] = useState(null);

   useEffect(() => {
  if (!name) return; // Safety check: don't fetch if no name is provided

  fetch(`https://pokeapi.co/api/v2/pokemon/${name.toLowerCase()}`)
    .then((res) => {
      if (!res.ok) throw new Error("Pokémon not found");
      return res.json();
    })
    .then((data) => setPokemon(data))
    .catch((err) => console.log("Error:", err));
}, [name]);

    if (!pokemon) return <p>Looking for Pokemon...</p>;
    
   return (
    <div>
      <h1>{pokemon.name}</h1>
      <img src={pokemon.sprites.front_default} alt={pokemon.name} />
    </div>
  );
};


  const [searchTerm, setSearchTerm] = useState("")
  let navigate = useNavigate

  const handleSearch = (e) => {
    if (e.key === 'Enter' && searchTerm) {
      navigate(`pokemon${searchTerm.toLowerCase()}`)
    }
  }



const [darkMode, setDarkMode] = useState(true);

const toggleTheme = () => {
    const nextMode = !darkMode; 
    setDarkMode(nextMode);
    document.body.classList.toggle('light-mode');
    localStorage.setItem('theme', nextMode ? 'dark' : 'light');
  };


useEffect(() => {
  const savedTheme = localStorage.getItem('theme'); 
  if(savedTheme === 'light') {
    setDarkMode(false); 
    document.body.classList.add('light-mode'); 
  }
}, [])






  return (
    
    
    <nav>
      <div className="nav-actions">
      <input type="text" placeholder="Search Pokémon" value={searchTerm} 
      onChange={(e) => setSearchTerm(e.target.value)}
      onKeyDown={handleSearch}
      />
    </div>
 <div className="logo">
      <figure>
  <Link to="/"><img src={Logo} alt="" style={{ width: '50px' }}/></Link>
    </figure>
    </div>
   
    {/* NAV LINKS */}
   <div className="nav-links">
        <Link to="/">Home</Link>
        <Link to="/about">About</Link>
        <Link to="/contact">Contact</Link>
        <Link to="/feedback">Feedback</Link>
      </div>
     

    
<div className="nav-actions">
    <button onClick={toggleTheme}>
          {darkMode ? '☀️' : '🌙'}
        </button>
</div>

    </nav>
    
);
};

export default Nav
